/* Orchestrator pattern (Node.js — more complete) */
const { v4: uuid } = require('uuid')
const store = require('./sagaStore') // durability

async function startOrderSaga(order) {
  const sagaId = uuid()
  await store.create(sagaId, { status: 'in-progress', step: 'charge' })
  try {
    await payments.charge(order.id)
    await store.update(sagaId, { step: 'reserve' })

    await inventory.reserve(order.id)
    await store.update(sagaId, { step: 'ship' })

    await shipping.create(order.id)
    await store.update(sagaId, { status: 'completed' })
  } catch (err) {
    await compensate(sagaId, order)
    await store.update(sagaId, { status: 'failed', error: err.message })
  }
}

async function compensate(sagaId, order) {
  const s = await store.get(sagaId)
  // run compensations based on s.step (reverse order)
  if (s.step === 'ship') {
    await shipping.cancel(order.id).catch(console.error)
    await inventory.compensateReserve(order.id).catch(console.error)
    await payments.refund(order.id).catch(console.error)
  }
}
